'use strict';

// Minimal stand-in for the real date-fns. A legitimate dependency with an
// ordinary build/prepare toolchain — nothing here should ever be flagged.

function addDays(date, amount) {
  const d = new Date(date.getTime());
  d.setDate(d.getDate() + amount);
  return d;
}

function format(date, pattern) {
  const iso = new Date(date).toISOString();
  return pattern === 'yyyy-MM-dd' ? iso.slice(0, 10) : iso;
}

module.exports = { addDays, format };
